const CHILDREN_DATA = [
  {
    id: '1',
    name: 'Arjun Sharma',
    initials: 'AS',
    studyHours: 12,
    progress: 68,
    lastActive: '2 hours ago',
    status: 'On Track',
    statusColor: 'success',
